const { fetch } = require('undici');

function uniqueKey() {
  const now = new Date()
  const date = now.toISOString().slice(0, 10)
  const ms = now % 86400000
  const rand = String(Math.floor(Math.random() * 1000)).padStart(3, '0')
  return `${date}_${ms}_${rand}`
}
const key = uniqueKey()

let configuration

$("Products Sheet Collection").all().forEach((product) => {
  if (
    product.json.Collection === $("Collection Form").first().json.Collection &&
    product.json.Installation_Type === $("Installation Type Form").first().json["Installation Type"] &&
    product.json.Model === $("Model Form").first().json.Model &&
    String(product.json.LW) === $("Dimension Form").first().json.Dimension &&
    product.json.Deck_Feature === $("Deck Feature Form").first().json["Deck Feature"] &&
    product.json.Handing === $("Handing Form").first().json.Handing &&
    product.json.Color === $("Color Form").first().json.Color &&
    product.json.Surface_Finish === $("Surface Finish Form").first().json["Surface Finish"].split(',')[0] &&
    product.json.Line === $("Line Form").first().json["Line"]
  ) {
    configuration = { base: product.json, co_num: $("Customer Order Form").first().json['Customer Order'], options: [] }
  }
})

await fetch(`http://localhost:7379/set/${key}/${encodeURIComponent(JSON.stringify(configuration))}`);

return { configuration, key }

